import FixtureList from "../components/fixture/fixture-list";
import SeasonSummary from "../components/season/season-summary";
import TigersFixtures from '../data/fixtures/fixtures'
import React, { useEffect, useState } from 'react';
import { GetSeasons } from "../services/seasonservice";
import { Season } from "../data/seasons/season";

const Home = () => {
    const [data, setData] = useState<Season[] | null>(null);

    useEffect(() => {
        GetSeasons().then(data => setData(data));
    }, []);


    return(
        <>
            <h3>Tigers Results</h3>
            <FixtureList fixturesToShow={TigersFixtures}></FixtureList>   
            <SeasonSummary fixtures={TigersFixtures}/>
            <div>
                {   data ? data.map((item) => (
                        <>
                            <div>{item.id}</div>
                            <div>{item.ageGroup}</div>
                            <div>{item.startYear}</div>
                            <div>{item.endYear}</div>
                        </>
                    )) : <p>Loading...</p>}
            </div>
        </>
    )
}
export default Home;
